var userConnection = Get<UserConnection>("UserConnection");
var log = new CustomLog(userConnection, $"Auto_Activation_UpdatePostDelivery");
var lineDetail = new LineDetail(UserConnection);

string soNumber = Get<string>("SONumber");
string serialNumber = string.Empty;
Guid submissionId = Guid.Empty;
Guid dealerId = Guid.Empty;
string salesPersonEmail = string.Empty;

try {
    List<LineDetail> lineDetails = GetLineDetail(userConnection, soNumber);
    if(lineDetails.Count == 0) {
        return true;
    }

    submissionId = lineDetails.FirstOrDefault().SubmissionId;
    serialNumber = lineDetails.FirstOrDefault().SerialNumber;
    dealerId = lineDetails.FirstOrDefault().Dealer?.Id ?? Guid.Empty;
    salesPersonEmail = GetSalesPersonEmail(userConnection, dealerId);
    string msisdnList = string.Join(", ", lineDetails.Select(item => item.MSISDN).ToArray());
	
    log.AddMessage($"Auto Activation is Start. SO Nummber: {soNumber}. Submission Id: {submissionId}. Serial Number: {serialNumber}. MSISDN: {msisdnList}.", true);

    List<Guid> lineDetailIds = lineDetails.Select(item => item.Id).ToList();
    foreach (Guid id in lineDetailIds) {
        new Update(userConnection, "DgLineDetail")
            .Set("DgReleased", Column.Parameter(true))
            .Set("DgReleasedDate", Column.Parameter(DateTime.UtcNow))
            .Set("DgReleasedById", Column.Parameter(userConnection.CurrentUser.ContactId))
        .Where("Id").IsEqual(Column.Parameter(id))
        .Execute();
    }

    var lineActivation = new LineActivation(userConnection, lineDetailIds);
    var result = lineActivation.Activation().GetAwaiter().GetResult();
    
    string logMessage = result.Message;
    string emailMessage = result.Message;
    try {
        var jsonMessage = JsonConvert.DeserializeObject<List<string>>(result.Message);
        logMessage = string.Join(
            Environment.NewLine, 
            jsonMessage
                .Select(item => item
                    .Replace("<br>", Environment.NewLine)
                    .Replace("<ul>", "")
                    .Replace("</ul>", Environment.NewLine)
                    .Replace("<li>", "=> ")
                    .Replace("</li>", Environment.NewLine)
                )
                .ToArray()
        );
        emailMessage = string.Join("<br><br>", jsonMessage.ToArray());
    } catch (Exception e) {}

    if(!result.Success) {
        log.AddMessage($"There were several errors during the activation process", true);
        log.AddMessage($"Error: {Environment.NewLine}{logMessage}", true);
        log.AddMessage($"Send email error notification to {salesPersonEmail}", true);
        
        SendEmail(userConnection, salesPersonEmail, serialNumber, soNumber, emailMessage);
    } else {
        log.AddMessage($"Activation is success for all line selected", true);
    }

    log.AddMessage($"Auto Activation for {soNumber} finish", true);
} catch (Exception e) {
    Set("Message", e.ToString());
    log.AddMessage($"Auto Activation is Failed: {Environment.NewLine}{e.ToString()}", true);

    log.AddMessage($"Send email error notification to {salesPersonEmail}", true);
    SendEmail(userConnection, salesPersonEmail, serialNumber, soNumber, e.ToString());
} finally {
    log.SaveToFile();
}

return true;

