public void SendEmail(UserConnection UserConnection, string SalespersonEmail, string SerialNumber, string SONumber, string ErrorMessage)
{
	if(string.IsNullOrEmpty(SalespersonEmail)) {
		return;
	}
	
	string email = Terrasoft.Core.Configuration.SysSettings.GetValue<string>(UserConnection, "DgEmailNotification_AutoActivationFailed", string.Empty);
    string message = $"Hi,"
        + "<br>Kindly rectify below error and perform manual provisioning for line activation. <br><br>"
        + ErrorMessage
        + $"<br><br>This message is auto-generated by NCCF.";

    var param = new MailParam() {
        Subject = $"NCCF error in auto provisioning during Order Simcard for {SerialNumber} | {SONumber}",
        Message = message,
        To = SalespersonEmail,
        CC = email,
        DefaultFooterMessage = true
    };

    Mail.Send(UserConnection, "nccf2-crm@celcomdigi.com", param);
}

public List<LineDetail> GetLineDetail(UserConnection UserConnection, string SONumber)
{
    var result = new List<LineDetail>();

    var esq = new EntitySchemaQuery(UserConnection.EntitySchemaManager, "DgLineDetail");
    var columns = new Dictionary<string, EntitySchemaQueryColumn>();

    columns.Add("Id", esq.AddColumn("Id"));
    columns.Add("No", esq.AddColumn("DgNo"));
    columns.Add("LineId", esq.AddColumn("DgLineId"));
    columns.Add("MSISDN", esq.AddColumn("DgMSISDN"));
    columns.Add("SubmissionId", esq.AddColumn("DgSubmission.Id"));
    columns.Add("SerialNumber", esq.AddColumn("DgSubmission.DgSerialNumber"));
    columns.Add("Dealer_Id", esq.AddColumn("DgSubmission.DgCRMGroup.DgDealer.Id"));

    columns["No"].OrderByAsc(0);
    columns["LineId"].OrderByAsc(1);

    var filterActivation = new EntitySchemaQueryFilterCollection(esq, LogicalOperationStrict.Or);
    filterActivation.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgActivationStatus", LookupConst.ActivationStatus.NotActivated));
    filterActivation.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgActivationStatus", LookupConst.ActivationStatus.Fail));
    filterActivation.Add(esq.CreateFilterWithParameters(FilterComparisonType.IsNull, "DgActivationStatus"));
    esq.Filters.Add(filterActivation);

    var filterDeviceIMEI = new EntitySchemaQueryFilterCollection(esq, LogicalOperationStrict.And);
    filterDeviceIMEI.Add(esq.CreateFilterWithParameters(FilterComparisonType.IsNotNull, "DgDeviceIMEI"));
    filterDeviceIMEI.Add(esq.CreateFilterWithParameters(FilterComparisonType.NotEqual, "DgDeviceIMEI", string.Empty));

    var filterSimCardSerialNo = new EntitySchemaQueryFilterCollection(esq, LogicalOperationStrict.And);
    filterSimCardSerialNo.Add(esq.CreateFilterWithParameters(FilterComparisonType.IsNotNull, "DgSIMCardNumber"));
    filterSimCardSerialNo.Add(esq.CreateFilterWithParameters(FilterComparisonType.NotEqual, "DgSIMCardNumber", string.Empty));

    var filterIMEI = new EntitySchemaQueryFilterCollection(esq, LogicalOperationStrict.Or);
    filterIMEI.Add(filterDeviceIMEI);
    filterIMEI.Add(filterSimCardSerialNo);
    esq.Filters.Add(filterIMEI);

    var filterSODoId = new EntitySchemaQueryFilterCollection(esq, LogicalOperationStrict.And);
    filterSODoId.Add(esq.CreateFilterWithParameters(FilterComparisonType.IsNotNull, "DgSODoID"));
    filterSODoId.Add(esq.CreateFilterWithParameters(FilterComparisonType.NotEqual, "DgSODoID", string.Empty));
    esq.Filters.Add(filterSODoId);

    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgReleased", false));
    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgReleasedToIPL", true));
    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.IsNotNull, "DgPreDeliveryDate"));
    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgDeliveryStatus.Id", LookupConst.DeliveryStatus.InTransit));
    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgSubmission.DgSubmissionType.Id", LookupConst.SubmissionType.NEW));
    esq.Filters.Add(esq.CreateFilterWithParameters(FilterComparisonType.Equal, "DgSOID", SONumber));

    var entities = esq.GetEntityCollection(UserConnection);
    foreach(var entity in entities) {
        var data = new LineDetail();
        data.Id = entity.GetTypedColumnValue<Guid>(columns["Id"].Name);
        data.MSISDN = entity.GetTypedColumnValue<string>(columns["MSISDN"].Name);
        data.SubmissionId = entity.GetTypedColumnValue<Guid>(columns["SubmissionId"].Name);
        data.SerialNumber = entity.GetTypedColumnValue<string>(columns["SerialNumber"].Name);
        data.Dealer = new DgMasterData.Lookup() {
            Id = entity.GetTypedColumnValue<Guid>(columns["Dealer_Id"].Name)
        };

        result.Add(data);
    }

    return result;
}

public string GetSalesPersonEmail(UserConnection UserConnection, Guid DealerId)
{
    var esq = new EntitySchemaQuery(UserConnection.EntitySchemaManager, "DgDealer");
    var columns = new Dictionary<string, EntitySchemaQueryColumn>();

    columns.Add("SalespersonEmail", esq.AddColumn("DgSalesPersonEmail"));

    var entity = esq.GetEntity(UserConnection, DealerId);
    
    return entity.GetTypedColumnValue<string>(columns["SalespersonEmail"].Name);
}
